CREATE TABLE motorcycles (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  plate_number TEXT UNIQUE NOT NULL,        
  vehicle_name TEXT NOT NULL,               
  chassis_number TEXT NOT NULL,             
  mileage INTEGER NOT NULL,                 
  model_year INTEGER NOT NULL,              
  insurance_company TEXT NOT NULL,          
  insurance_start_date TEXT NOT NULL,       
  insurance_end_date TEXT NOT NULL,         
  driving_range TEXT NOT NULL,              
  owner_name TEXT NOT NULL,                 
  insurance_fee INTEGER NOT NULL,           
  vehicle_price INTEGER NOT NULL,           
  status TEXT DEFAULT 'available',          
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
, daily_rental_fee INTEGER DEFAULT 0, usage_notes TEXT, inspection_start_date TEXT, inspection_end_date TEXT, monthly_fee INTEGER DEFAULT 0, contract_type_text TEXT DEFAULT '', deposit INTEGER DEFAULT 0, contract_start_date TEXT DEFAULT '', contract_end_date TEXT DEFAULT '', certificate_photo TEXT);
