  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP, id_card_photo TEXT, deleted_at DATETIME DEFAULT NULL, insurance_age_limit TEXT,
  FOREIGN KEY (motorcycle_id) REFERENCES motorcycles(id),
  FOREIGN KEY (customer_id) REFERENCES customers(id)
);
